@namespace Lumeo

<div class="@ContainerClass"
     role="progressbar"
     aria-valuenow="@((int)Math.Round(ClampedValue))"
     aria-valuemin="0"
     aria-valuemax="100"
     @attributes="AdditionalAttributes"
     style="@ContainerStyle">
    <svg width="@Size" height="@Size"
         viewBox="0 0 @Size @Size"
         xmlns="http://www.w3.org/2000/svg">
        @* Track circle *@
        <circle cx="@Cx" cy="@Cy" r="@Radius"
                fill="none"
                stroke="var(--color-@TrackColor, var(--color-muted))"
                stroke-width="@Thickness" />
        @* Value circle *@
        <circle cx="@Cx" cy="@Cy" r="@Radius"
                fill="none"
                stroke="var(--color-@Color, var(--color-primary))"
                stroke-width="@Thickness"
                stroke-linecap="@(RoundedCaps ? "round" : "butt")"
                stroke-dasharray="@DashArray"
                stroke-dashoffset="@DashOffset"
                transform="rotate(-90 @Cx @Cy)"
                style="transition: stroke-dashoffset 0.3s ease;" />
    </svg>
    @* Centre content *@
    @if (LabelContent is not null)
    {
        <div class="absolute inset-0 flex items-center justify-center">
            @LabelContent
        </div>
    }
    else if (ShowLabel)
    {
        <span class="absolute inset-0 flex items-center justify-center text-foreground font-medium"
              style="font-size: @(Size / 5)px;">
            @((int)Math.Round(ClampedValue))%
        </span>
    }
</div>

@code {
    /// <summary>The progress value, clamped to 0–100. <c>NaN</c> is treated as 0.</summary>
    [Parameter] public double Value { get; set; }
    /// <summary>Diameter of the ring in pixels (both width and height of the SVG). Default 64.</summary>
    [Parameter] public int Size { get; set; } = 64;
    /// <summary>Stroke width of the ring in pixels. Default 6.</summary>
    [Parameter] public int Thickness { get; set; } = 6;
    /// <summary>Theme color token for the filled arc, resolved as <c>var(--color-{Color})</c>. Default <c>"primary"</c>.</summary>
    [Parameter] public string Color { get; set; } = "primary";
    /// <summary>Theme color token for the unfilled track, resolved as <c>var(--color-{TrackColor})</c>. Default <c>"muted"</c>.</summary>
    [Parameter] public string TrackColor { get; set; } = "muted";
    /// <summary>Shows the rounded percentage as centered text. Ignored when <see cref="LabelContent"/> is set.</summary>
    [Parameter] public bool ShowLabel { get; set; }
    /// <summary>Custom content rendered centered inside the ring, replacing the built-in percentage label.</summary>
    [Parameter] public RenderFragment? LabelContent { get; set; }
    /// <summary>Uses rounded (<c>stroke-linecap: round</c>) instead of squared (<c>butt</c>) ends on the filled arc. Default <see langword="true"/>.</summary>
    [Parameter] public bool RoundedCaps { get; set; } = true;
    /// <summary>Additional CSS classes merged onto the outer container.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the outer container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private double ClampedValue => Math.Clamp(double.IsNaN(Value) ? 0.0 : Value, 0.0, 100.0);

    private double Cx => Size / 2.0;
    private double Cy => Size / 2.0;
    private double Radius => (Size - Thickness) / 2.0;
    private double Circumference => 2 * Math.PI * Radius;

    private string DashArray
        => Circumference.ToString(System.Globalization.CultureInfo.InvariantCulture);

    private string DashOffset
    {
        get
        {
            var offset = Circumference * (1.0 - ClampedValue / 100.0);
            return offset.ToString(System.Globalization.CultureInfo.InvariantCulture);
        }
    }

    private string ContainerClass
        => Lumeo.Cx.Merge("relative inline-flex items-center justify-center", Class);

    private string ContainerStyle
        => $"width: {Size}px; height: {Size}px;";
}
